#!/usr/bin/env python3
import re

def cleanup_serializers_file():
    filepath = r'c:\Users\Vidhu\Documents\GitHub\miisky_project\backend\website\serializers.py'
    
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()
    
    original_size = len(content)
    
    # List of section patterns to remove
    sections = [
        (r'# ===========================================================================\n# 3\. NAVIGATION MENU\n.*?(?=# ===========================================================================\n# 4\.)', 'Section 3'),
        (r'# ===========================================================================\n# 5\. HEALTH FOOD.*?(?=# ===========================================================================\n# 6\.)', 'Section 5'),
        (r'# ===========================================================================\n# 6\. HEALTH FOOD CONCEPT.*?(?=# ===========================================================================\n# 7\.)', 'Section 6'),
        (r'# ===========================================================================\n# 10\. CALLBACK.*?(?=# ===========================================================================\n# 11\.)', 'Section 10'),
        (r'# ===========================================================================\n# 11\. CONTACT.*?(?=# ===========================================================================\n# 12\.)', 'Section 11'),
        (r'# ===========================================================================\n# 12\. NEWSLETTER.*?(?=# ===========================================================================\n# 13\.)', 'Section 12'),
        (r'# ===========================================================================\n# 13\. TESTIMONIALS.*?(?=# ===========================================================================\n# 14\.)', 'Section 13'),
        (r'# ===========================================================================\n# 19\. VISION.*?(?=# ===========================================================================\n# 20\.)', 'Section 19'),
        (r'# ===========================================================================\n# 20\. AI CHATBOT.*?(?=# ===========================================================================\n# 21\.)', 'Section 20'),
        (r'# ===========================================================================\n# 21\. STAT COUNTERS.*?(?=# ===========================================================================\n# 22\.)', 'Section 21'),
        (r'# ===========================================================================\n# 22\. MOBILE APP.*?(?=# ===========================================================================\n# 23\.)', 'Section 22'),
        (r'# ===========================================================================\n# 23\. VALUE.*?(?=# ===========================================================================\n# 24\.)', 'Section 23'),
        (r'# ===========================================================================\n# 24\. PRODUCTS.*?(?=# ===========================================================================\n# 25\.)', 'Section 24'),
        (r'# ===========================================================================\n# 25\. SERVICES.*?(?=# ===========================================================================\n# 26\.)', 'Section 25'),
        (r'# ===========================================================================\n# 26\. GST.*?(?=# ===========================================================================\n# 27\.)', 'Section 26'),
        (r'# ===========================================================================\n# 27\. PRESENTATIONS.*?(?=# ===========================================================================\n# 28\.)', 'Section 27'),
        (r'# ===========================================================================\n# 28\. WORKFLOW SUB-CATEGORIES.*?(?=# ===========================================================================\n# 29\.)', 'Section 28'),
        (r'# ===========================================================================\n# 29\. MY HEALTH.*?(?=# ===========================================================================\n# 30\.)', 'Section 29'),
        (r'# ===========================================================================\n# 30\. NUTRITIONIST.*?(?=# ===========================================================================\n# 31\.)', 'Section 30'),
        (r'# ===========================================================================\n# 31\. MICRO KITCHEN.*?(?=# ===========================================================================\n# 32\.)', 'Section 31'),
        (r'# ===========================================================================\n# 32\. SUPPLY CHAIN.*?(?=# ===========================================================================\n# 33\.)', 'Section 32'),
        (r'# ===========================================================================\n# 33\. AI CHAT SESSIONS.*?(?=# ===========================================================================\n# 34\.)', 'Section 33'),
        (r'# ===========================================================================\n# 34\. USER SUGGESTIONS.*?(?=# ===========================================================================\n# 35\.)', 'Section 34'),
        (r'# ===========================================================================\n# 35\. WORKFLOW SUB-ITEMS.*?(?=# ===========================================================================\n# 36\.)', 'Section 35'),
        (r'# ===========================================================================\n# 36\. GST LEADERS.*?(?=# ===========================================================================\n# 37\.)', 'Section 36'),
        (r'# ===========================================================================\n# 37\..*?(?=# ===========================================================================\n# 38\.)', 'Section 37'),
        (r'# ===========================================================================\n# 38\..*?(?=# ===========================================================================)', 'Section 38'),
    ]
    
    for pattern, name in sections:
        content = re.sub(pattern, '', content, flags=re.DOTALL)
    
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(content)
    
    removed_lines = (original_size - len(content)) // 100
    print(f"[serializers.py] Removed ~{removed_lines } lines")

if __name__ == '__main__':
    cleanup_serializers_file()
